mapper.select:
SELECT p.id, p.title, p.sub_title AS subTitle, p.category_id AS categoryId, c.name AS categoryName, p.images AS images, p.price, IFNULL(p.stock, 0) AS stock, p.status, p.create_time AS createTime, p.update_time AS updateTime FROM pms_product p LEFT JOIN pms_product_category c ON p.category_id = c.id
AND p.id = #{param.productId}
AND p.title LIKE CONCAT('%', #{param.keyword}, '%')
AND p.category_id = #{param.categoryId}
AND p.status = #{param.status}
AND p.price >= #{param.priceMin}
AND p.price <= #{param.priceMax}
AND p.create_time >= CONCAT(#{param.createTimeStart}, ' 00:00:00')
AND p.create_time <= CONCAT(#{param.createTimeEnd}, ' 23:59:59')
ORDER BY p.create_time DESC

mapper.update:
UPDATE pms_product
SET lock_stock = lock_stock + #{quantity}
WHERE id = #{productId}
  AND status = 1
  AND (stock - lock_stock) >= #{quantity}

UPDATE pms_product
SET stock = stock - #{quantity},
    lock_stock = lock_stock - #{quantity},
    sale = sale + #{quantity}
WHERE id = #{productId}
  AND lock_stock >= #{quantity}

UPDATE pms_product
SET lock_stock = lock_stock - #{quantity}
WHERE id = #{productId}
  AND lock_stock >= #{quantity}
